const body = $('Webhook Contact Form').first().json.body;
const ghFile = $('GET tracking.json').first().json;

// Decode current tracking.json content
const currentContent = JSON.parse(Buffer.from(ghFile.content, 'base64').toString('utf8'));

// Build new project entry
const today = new Date().toISOString().split('T')[0];
const newProject = {
  code: body.projectCode,
  client: body.name,
  project: body.project || 'Projet en cours de définition',
  email: body.email,
  company: body.company || '',
  startDate: today,
  estimatedEnd: null,
  currentPhase: 1,
  phases: [
    { id: 1, label: 'Brief & Analyse',  desc: 'Recueil des besoins, cadrage du projet',       status: 'active', date: today },
    { id: 2, label: 'Conception',        desc: 'Architecture, maquettes, planning',             status: 'pending', date: null },
    { id: 3, label: 'Développement',     desc: 'Implémentation, intégrations',                 status: 'pending', date: null },
    { id: 4, label: 'Tests & Recette',   desc: 'Tests, corrections, validation client',        status: 'pending', date: null },
    { id: 5, label: 'Déploiement',       desc: 'Mise en ligne, configuration production',      status: 'pending', date: null },
    { id: 6, label: 'Livré ✓',          desc: 'Documentation remise, support post-livraison', status: 'pending', date: null }
  ],
  updates: [
    { date: today, message: `Bonjour ${body.name.split(' ')[0]} ! Votre demande a bien été reçue. Nous revenons vers vous sous 24h avec une première analyse.` }
  ]
};

currentContent.push(newProject);

// Encode updated file
const updatedContent = Buffer.from(JSON.stringify(currentContent, null, 2)).toString('base64');

return [{ json: { updatedContent, sha: ghFile.sha, newProject } }];
